parameters.jsCode:
const resp = $input.first().json;
const url = $('PG: Pages without description').item.json.url;

let content = '';
try {
  content = resp.content[0].text;
  // Strip markdown if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(content);
  return [{ json: {
    url: url,
    description: (parsed.description || '').substring(0, 200),
    h1: (parsed.h1 || '').substring(0, 100),
    faq: JSON.stringify(parsed.faq || []),
    article: (parsed.article || '').substring(0, 2000),
    ok: true
  }}];
} catch(e) {
  return [{ json: { url: url, ok: false, error: e.message, raw: content.substring(0, 200) } }];
}

const d = $input.first().json;
if (!d.ok) return [{ json: { sql: null, skipped: true, url: d.url, error: d.error } }];

// Escape single quotes for PostgreSQL
const esc = (s) => (s || '').replace(/'/g, "''");

const sql = `UPDATE page_seo SET
  description = '${esc(d.description)}',
  h1 = '${esc(d.h1)}',
  faq = '${esc(d.faq)}'::jsonb,
  article = '${esc(d.article)}',
  updated_at = now()
WHERE url = '${esc(d.url)}' AND lang = 'ru'`;

return [{ json: { sql, url: d.url, ok: true } }];

const all = $input.all();
const ok = all.filter(i => i.json.success === true || i.json.success === 'true').length;
const total = all.length;
const date = new Date().toISOString().slice(0,10);
return [{ json: { ok, total, date } }];
